#include <vector>
#include <numeric>
#include <algorithm>

using namespace std;

long long solve(vector<long long> nums, vector<vector<long long>> queries) {
    const long long MOD = 1000000007;
    for (const auto& query : queries) {
        long long li = query[0], ri = query[1], ki = query[2], vi = query[3];
        long long idx = li;
        while (idx <= ri) {
            nums[idx] = (nums[idx] * vi) % MOD;
            idx += ki;
        }
    }
    return accumulate(nums.begin(), nums.end(), 0LL, bitwise_xor<long long>());
}
